SELECT COUNT(*)
FROM care_item ci


        ci.care_level_id = #{careLevelId}

SELECT ci.id, ci.item_name AS itemName, ci.care_level_id AS careLevelId, cl.level_name AS levelName, ci.frequency, ci.description, ci.sort_order AS sortOrder, ci.create_time AS createTime FROM care_item ci INNER JOIN ( SELECT ci2.id FROM care_item ci2
ci2.care_level_id = #{careLevelId}
ORDER BY ci2.sort_order ASC, ci2.id ASC LIMIT #{offset}, #{pageSize} ) page_ids ON ci.id = page_ids.id LEFT JOIN care_level cl ON ci.care_level_id = cl.id ORDER BY ci.sort_order ASC, ci.id ASC

SELECT ci.id, ci.item_name AS itemName, ci.care_level_id AS careLevelId, cl.level_name AS levelName, ci.frequency, ci.description, ci.sort_order AS sortOrder, ci.create_time AS createTime FROM care_item ci LEFT JOIN care_level cl ON ci.care_level_id = cl.id
ci.care_level_id = #{careLevelId}
ORDER BY ci.sort_order ASC, ci.id ASC
